  1→/**
  2→ * sequant init - Initialize Sequant in a project
  3→ */
  4→
  5→import chalk from "chalk";
  6→import inquirer from "inquirer";
  7→import { ui, colors } from "../lib/cli-ui.js";
  8→import {
  9→  detectStack,
 10→  detectAllStacks,
 11→  getStackConfig,
 12→  detectPackageManager,
 13→  getPackageManagerCommands,
 14→  STACKS,
 15→} from "../lib/stacks.js";
 16→import { copyTemplates } from "../lib/templates.js";
 17→import { createManifest } from "../lib/manifest.js";
 18→import { saveConfig } from "../lib/config.js";
 19→import { createDefaultSettings } from "../lib/settings.js";
 20→import { detectAndSaveConventions } from "../lib/conventions-detector.js";
 21→import { fileExists, ensureDir, readFile, writeFile } from "../lib/fs.js";
 22→import { generateAgentsMd, writeAgentsMd } from "../lib/agents-md.js";
 23→import {
 24→  commandExists,
 25→  isGhAuthenticated,
 26→  getInstallHint,
 27→} from "../lib/system.js";
 28→import {
 29→  shouldUseInteractiveMode,
 30→  getNonInteractiveReason,
 31→} from "../lib/tty.js";
 32→import {
 33→  checkAllDependencies,
 34→  displayDependencyStatus,
 35→  runSetupWizard,
 36→  shouldRunSetupWizard,
 37→} from "../lib/wizard.js";
 38→import { saveStackConfig, type StackConfigFile } from "../lib/stack-config.js";
 39→
 40→/**
 41→ * Check prerequisites and display warnings
 42→ */
 43→function checkPrerequisites(): { warnings: string[]; suggestions: string[] } {
 44→  const warnings: string[] = [];
 45→  const suggestions: string[] = [];
 46→
 47→  // Check for gh CLI
 48→  if (!commandExists("gh")) {
 49→    warnings.push(
 50→      "GitHub CLI (gh) is not installed. Required for issue workflows.",
 51→    );
 52→    suggestions.push(`Install: ${getInstallHint("gh")}`);
 53→  } else if (!isGhAuthenticated()) {
 54→    warnings.push("GitHub CLI is not authenticated.");
 55→    suggestions.push("Run: gh auth login");
 56→  }
 57→
 58→  // Check for jq (optional)
 59→  if (!commandExists("jq")) {
 60→    suggestions.push(
 61→      `Optional: Install jq for faster JSON parsing (${getInstallHint("jq")})`,
 62→    );
 63→  }
 64→
 65→  return { warnings, suggestions };
 66→}
 67→
 68→interface InitOptions {
 69→  stack?: string;
 70→  yes?: boolean;
 71→  force?: boolean;
 72→  interactive?: boolean;
 73→  skipSetup?: boolean;
 74→  noSymlinks?: boolean;
 75→  agentsMd?: boolean;
 76→}
 77→
 78→/**
 79→ * Entries to add to .gitignore
 80→ */
 81→const GITIGNORE_ENTRIES = [
 82→  "",
 83→  "# Sequant runtime data (logs, settings)",
 84→  ".sequant/",
 85→];
 86→
 87→/**
 88→ * Update .gitignore with Sequant entries
 89→ */
 90→async function updateGitignore(): Promise<boolean> {
 91→  const gitignorePath = ".gitignore";
 92→  let content = "";
 93→
 94→  if (await fileExists(gitignorePath)) {
 95→    content = await readFile(gitignorePath);
 96→
 97→    // Check if already has .sequant/
 98→    if (content.includes(".sequant/")) {
 99→      return false; // Already configured
100→    }
101→  }
102→
103→  // Append entries
104→  const newContent =
105→    content.trimEnd() + "\n" + GITIGNORE_ENTRIES.join("\n") + "\n";
106→  await writeFile(gitignorePath, newContent);
107→  return true;
108→}
109→
110→/**
111→ * Log a default value being used in non-interactive mode
112→ */
113→function logDefault(label: string, value: string): void {
114→  console.log(chalk.blue(`📦 ${label}: ${value} (default)`));
115→}
116→
117→export async function initCommand(options: InitOptions): Promise<void> {
118→  // Show banner
119→  console.log(ui.banner());
120→  console.log(colors.success("\nInitializing Sequant...\n"));
121→
122→  // Determine if we should use interactive mode
123→  const useInteractive = shouldUseInteractiveMode(options.interactive);
124→  const skipPrompts = options.yes || !useInteractive;
125→
126→  // Show non-interactive mode message if applicable
127→  if (!useInteractive && !options.yes) {
128→    const reason = getNonInteractiveReason();
129→    console.log(
130→      chalk.yellow(
131→        `⚡ Non-interactive mode detected${reason ? ` (${reason})` : ""}`,
132→      ),
133→    );
134→    console.log(
135→      chalk.gray("   Using defaults. Use --interactive to force prompts.\n"),
136→    );
137→  }
138→
139→  // Check dependencies and run setup wizard if needed
140→  const depCheckResult = checkAllDependencies();
141→  let wizardRemainingIssues: string[] = [];
142→
143→  if (
144→    shouldRunSetupWizard({ skipSetup: options.skipSetup, yes: options.yes })
145→  ) {
146→    // Display dependency status
147→    displayDependencyStatus(depCheckResult);
148→
149→    // Run wizard if there are missing required dependencies
150→    if (depCheckResult.hasMissing) {
151→      const wizardResult = await runSetupWizard(depCheckResult, {
152→        skipPrompts,
153→      });
154→      wizardRemainingIssues = wizardResult.remainingIssues;
155→    }
156→  } else if (options.skipSetup) {
157→    // User explicitly skipped - show brief status
158→    console.log(
159→      chalk.gray("Skipping dependency setup wizard (--skip-setup)\n"),
160→    );
161→  }
162→
163→  // Fall back to legacy warning system for any remaining issues
164→  const { warnings, suggestions } = checkPrerequisites();
165→
166→  // Only show warnings if wizard didn't already handle them or if there are remaining issues
167→  if (
168→    wizardRemainingIssues.length > 0 ||
169→    (options.skipSetup && warnings.length > 0)
170→  ) {
171→    if (wizardRemainingIssues.length > 0) {
172→      console.log(chalk.yellow("⚠️  Remaining setup issues:\n"));
173→      for (const issue of wizardRemainingIssues) {
174→        console.log(chalk.yellow(`   • ${issue}`));
175→      }
176→      console.log();
177→    } else if (warnings.length > 0) {
178→      console.log(chalk.yellow("⚠️  Prerequisites:\n"));
179→      for (const warning of warnings) {
180→        console.log(chalk.yellow(`   • ${warning}`));
181→      }
182→      for (const suggestion of suggestions.filter(
183→        (s) => !s.startsWith("Optional"),
184→      )) {
185→        console.log(chalk.gray(`     ${suggestion}`));
186→      }
187→      console.log();
188→    }
189→  }
190→
191→  // Check if already initialized
192→  const configExists = await fileExists(".claude/settings.json");
193→  if (configExists && !options.force) {
194→    console.log(
195→      chalk.yellow(
196→        "⚠️  Sequant appears to be already initialized (.claude/settings.json exists)",
197→      ),
198→    );
199→    console.log(chalk.gray("   Use --force to reinitialize\n"));
200→
201→    if (!skipPrompts) {
202→      const { proceed } = await inquirer.prompt([
203→        {
204→          type: "confirm",
205→          name: "proceed",
206→          message: "Continue anyway?",
207→          default: false,
208→        },
209→      ]);
210→      if (!proceed) {
211→        console.log(chalk.gray("Aborted."));
212→        return;
213→      }
214→    }
215→  }
216→
217→  // Detect or prompt for stack
218→  let stack = options.stack;
219→  let additionalStacks: string[] = [];
220→
221→  if (!stack) {
222→    // Check for multi-stack project in interactive mode
223→    const allDetectedStacks = !skipPrompts ? await detectAllStacks() : [];
224→
225→    if (allDetectedStacks.length > 1 && !skipPrompts) {
226→      // Multi-stack project detected - show checkbox selection
227→      console.log(
228→        chalk.blue(
229→          `\n🔍 Detected ${allDetectedStacks.length} stacks in this project:`,
230→        ),
231→      );
232→      for (const ds of allDetectedStacks) {
233→        const location = ds.path ? ` (${ds.path}/)` : " (root)";
234→        console.log(
235→          chalk.gray(
236→            `   • ${STACKS[ds.stack]?.displayName || ds.stack}${location}`,
237→          ),
238→        );
239→      }
240→      console.log();
241→
242→      // Multi-stack selection prompt
243→      const { selectedStacks } = await inquirer.prompt([
244→        {
245→          type: "checkbox",
246→          name: "selectedStacks",
247→          message: "Select stacks to include in your constitution:",
248→          choices: allDetectedStacks.map((ds) => ({
249→            name: `${STACKS[ds.stack]?.displayName || ds.stack}${ds.path ? ` (${ds.path}/)` : " (root)"}`,
250→            value: ds.stack,
251→            checked: true, // Pre-select all detected stacks
252→          })),
253→          validate: (answer: string[]) => {
254→            if (answer.length < 1) {
255→              return "You must select at least one stack.";
256→            }
257→            return true;
258→          },
259→        },
260→      ]);
261→
262→      // First selected stack is the primary
263→      if (selectedStacks.length > 0) {
264→        stack = selectedStacks[0];
265→        additionalStacks = selectedStacks.slice(1);
266→      }
267→
268→      // Confirm or change primary stack if multiple selected
269→      if (selectedStacks.length > 1) {
270→        const { primaryStack } = await inquirer.prompt([
271→          {
272→            type: "list",
273→            name: "primaryStack",
274→            message:
275→              "Which stack should be the primary? (determines dev URL and commands)",
276→            choices: selectedStacks.map((s: string) => ({
277→              name: STACKS[s]?.displayName || s,
278→              value: s,
279→            })),
280→          },
281→        ]);
282→        stack = primaryStack;
283→        additionalStacks = selectedStacks.filter(
284→          (s: string) => s !== primaryStack,
285→        );
286→      }
287→    } else {
288→      // Single stack detection (original behavior)
289→      const detected = await detectStack();
290→      if (detected && skipPrompts) {
291→        stack = detected;
292→        logDefault("Detected stack", stack);
293→      } else if (detected && !skipPrompts) {
294→        const { confirmedStack } = await inquirer.prompt([
295→          {
296→            type: "list",
297→            name: "confirmedStack",
298→            message: `Detected ${detected} project. Is this correct?`,
299→            choices: [
300→              { name: `Yes, use ${detected}`, value: detected },
301→              { name: "No, let me choose", value: null },
302→            ],
303→          },
304→        ]);
305→        stack = confirmedStack;
306→      }
307→
308→      if (!stack && skipPrompts) {
309→        // No detection and skipping prompts: use generic as default
310→        stack = "generic";
311→        logDefault("Using stack", stack);
312→      } else if (!stack) {
313→        const { selectedStack } = await inquirer.prompt([
314→          {
315→            type: "list",
316→            name: "selectedStack",
317→            message: "Select your project stack:",
318→            choices: [
319→              { name: "Next.js / React", value: "nextjs" },
320→              { name: "Astro", value: "astro" },
321→              { name: "SvelteKit", value: "sveltekit" },
322→              { name: "Remix", value: "remix" },
323→              { name: "Nuxt", value: "nuxt" },
324→              { name: "Rust", value: "rust" },
325→              { name: "Python", value: "python" },
326→              { name: "Go", value: "go" },
327→              { name: "Generic (no stack-specific config)", value: "generic" },
328→            ],
329→          },
330→        ]);
331→        stack = selectedStack;
332→      }
333→    }
334→  }
335→
336→  // Display selected stacks
337→  if (additionalStacks.length > 0) {
338→    console.log(chalk.blue(`\n📋 Primary Stack: ${stack}`));
339→    console.log(chalk.blue(`   Additional: ${additionalStacks.join(", ")}`));
340→  } else {
341→    console.log(chalk.blue(`\n📋 Stack: ${stack}`));
342→  }
343→
344→  // Detect package manager
345→  const packageManager = await detectPackageManager();
346→  if (packageManager) {
347→    console.log(chalk.blue(`📦 Package Manager: ${packageManager}`));
348→  }
349→
350→  // Get stack config for default dev URL
351→  const stackConfig = getStackConfig(stack!);
352→  let devUrl = stackConfig.devUrl;
353→
354→  // Prompt for dev URL
355→  if (skipPrompts) {
356→    logDefault("Dev URL", devUrl);
357→  } else {
358→    const { inputDevUrl } = await inquirer.prompt([
359→      {
360→        type: "input",
361→        name: "inputDevUrl",
362→        message: "Development server URL:",
363→        default: devUrl,
364→      },
365→    ]);
366→    devUrl = inputDevUrl;
367→  }
368→
369→  // Show what will be created
370→  console.log(chalk.gray("\nWill create:"));
371→  console.log(chalk.gray("  .claude/"));
372→  console.log(chalk.gray("  ├── skills/         (14 workflow skills)"));
373→  console.log(chalk.gray("  ├── hooks/          (pre/post tool hooks)"));
374→  console.log(chalk.gray("  ├── memory/         (constitution & context)"));
375→  console.log(chalk.gray("  └── settings.json   (hooks configuration)"));
376→  console.log(chalk.gray("  .sequant/"));
377→  console.log(chalk.gray("  ├── settings.json   (run preferences)"));
378→  console.log(chalk.gray("  └── logs/           (workflow run logs)"));
379→  console.log(chalk.gray("  scripts/dev/"));
380→  console.log(chalk.gray("  └── *.sh            (worktree helpers)"));
381→  if (options.agentsMd !== false) {
382→    console.log(
383→      chalk.gray("  AGENTS.md           (universal agent instructions)"),
384→    );
385→  }
386→
387→  if (!skipPrompts) {
388→    const { confirm } = await inquirer.prompt([
389→      {
390→        type: "confirm",
391→        name: "confirm",
392→        message: "Proceed with installation?",
393→        default: true,
394→      },
395→    ]);
396→    if (!confirm) {
397→      console.log(chalk.gray("Aborted."));
398→      return;
399→    }
400→  }
401→
402→  // Create directories with spinner
403→  const dirSpinner = ui.spinner("Creating directories...");
404→  dirSpinner.start();
405→  await ensureDir(".claude/skills");
406→  await ensureDir(".claude/hooks");
407→  await ensureDir(".claude/memory");
408→  await ensureDir(".claude/.sequant");
409→  await ensureDir(".sequant/logs");
410→  await ensureDir("scripts/dev");
411→  dirSpinner.succeed("Created directories");
412→
413→  // Update .gitignore
414→  const gitignoreUpdated = await updateGitignore();
415→  if (gitignoreUpdated) {
416→    ui.printStatus("success", "Updated .gitignore with Sequant entries");
417→  }
418→
419→  // Save config with tokens
420→  const configSpinner = ui.spinner("Saving configuration...");
421→  configSpinner.start();
422→  const pmConfig = packageManager
423→    ? getPackageManagerCommands(packageManager)
424→    : getPackageManagerCommands("npm");
425→  const tokens = {
426→    DEV_URL: devUrl,
427→    PM_RUN: pmConfig.run, // e.g., "npm run", "bun run", "yarn", "pnpm run"
428→  };
429→  await saveConfig({
430→    tokens,
431→    stack: stack!,
432→    initialized: new Date().toISOString(),
433→  });
434→  configSpinner.succeed("Saved configuration");
435→
436→  // Save multi-stack configuration if additional stacks selected
437→  if (additionalStacks.length > 0) {
438→    const stackConfig: StackConfigFile = {
439→      primary: { name: stack! },
440→      additional: additionalStacks.map((name) => ({ name })),
441→    };
442→    await saveStackConfig(stackConfig);
443→    console.log(chalk.blue("📋 Saved multi-stack configuration"));
444→  }
445→
446→  // Create default settings
447→  const settingsSpinner = ui.spinner("Creating default settings...");
448→  settingsSpinner.start();
449→  await createDefaultSettings();
450→  settingsSpinner.succeed("Created default settings");
451→
452→  // Detect codebase conventions
453→  const conventionsSpinner = ui.spinner("Detecting codebase conventions...");
454→  conventionsSpinner.start();
455→  try {
456→    const conventions = await detectAndSaveConventions(process.cwd());
457→    const count = Object.keys(conventions.detected).length;
458→    conventionsSpinner.succeed(`Detected ${count} codebase conventions`);
459→  } catch {
460→    conventionsSpinner.warn("Could not detect conventions (non-blocking)");
461→  }
462→
463→  // Copy templates (with symlinks for scripts unless --no-symlinks)
464→  const templatesSpinner = ui.spinner("Copying templates...");
465→  templatesSpinner.start();
466→  const { scriptsSymlinked, symlinkResults } = await copyTemplates(
467→    stack!,
468→    tokens,
469→    {
470→      noSymlinks: options.noSymlinks,
471→      force: options.force,
472→      additionalStacks,
473→    },
474→  );
475→
476→  templatesSpinner.succeed("Copied templates");
477→
478→  // Report symlink status
479→  if (scriptsSymlinked) {
480→    ui.printStatus("success", "Created symlinks for scripts/dev/");
