  1→/**
  2→ * MCP client detection and configuration
  3→ *
  4→ * Detects installed MCP clients (Claude Desktop, Cursor, VS Code)
  5→ * and generates appropriate configuration entries for Sequant MCP server.
  6→ */
  7→
  8→import * as fs from "fs";
  9→import * as path from "path";
 10→import * as os from "os";
 11→
 12→export type McpClientType = "claude-desktop" | "cursor" | "vscode-continue";
 13→
 14→export interface McpClientInfo {
 15→  name: string;
 16→  clientType: McpClientType;
 17→  configPath: string;
 18→  exists: boolean;
 19→}
 20→
 21→/**
 22→ * Clients that need an explicit cwd because they don't run from the project directory.
 23→ */
 24→const CLIENTS_NEEDING_CWD: ReadonlySet<McpClientType> = new Set([
 25→  "claude-desktop",
 26→  "vscode-continue",
 27→]);
 28→
 29→/**
 30→ * Sequant MCP server configuration entry.
 31→ *
 32→ * @param options.projectDir - Absolute project path (used as cwd for clients that need it)
 33→ * @param options.clientType - Target client; determines whether cwd/env are included
 34→ */
 35→export function getSequantMcpConfig(options?: {
 36→  projectDir?: string;
 37→  clientType?: McpClientType;
 38→}): Record<string, unknown> {
 39→  const config: Record<string, unknown> = {
 40→    command: "npx",
 41→    args: ["sequant@latest", "serve"],
 42→  };
 43→
 44→  // Add cwd for clients that don't run from the project directory
 45→  if (options?.clientType && CLIENTS_NEEDING_CWD.has(options.clientType)) {
 46→    config.cwd = options.projectDir ?? process.cwd();
 47→  }
 48→
 49→  // Only include ANTHROPIC_API_KEY when it is actually set
 50→  if (process.env.ANTHROPIC_API_KEY) {
 51→    config.env = { ANTHROPIC_API_KEY: process.env.ANTHROPIC_API_KEY };
 52→  }
 53→
 54→  return config;
 55→}
 56→
 57→/**
 58→ * Detect which MCP-compatible clients are installed
 59→ */
 60→export function detectMcpClients(): McpClientInfo[] {
 61→  const clients: McpClientInfo[] = [];
 62→  const home = os.homedir();
 63→
 64→  // Claude Desktop
 65→  const claudeDesktopConfig =
 66→    process.platform === "darwin"
 67→      ? path.join(
 68→          home,
 69→          "Library",
 70→          "Application Support",
 71→          "Claude",
 72→          "claude_desktop_config.json",
 73→        )
 74→      : process.platform === "win32"
 75→        ? path.join(
 76→            home,
 77→            "AppData",
 78→            "Roaming",
 79→            "Claude",
 80→            "claude_desktop_config.json",
 81→          )
 82→        : path.join(home, ".config", "claude", "claude_desktop_config.json");
 83→
 84→  clients.push({
 85→    name: "Claude Desktop",
 86→    clientType: "claude-desktop",
 87→    configPath: claudeDesktopConfig,
 88→    exists: fs.existsSync(claudeDesktopConfig),
 89→  });
 90→
 91→  // Cursor
 92→  const cursorConfig = path.join(process.cwd(), ".cursor", "mcp.json");
 93→  clients.push({
 94→    name: "Cursor",
 95→    clientType: "cursor",
 96→    configPath: cursorConfig,
 97→    exists: fs.existsSync(path.join(process.cwd(), ".cursor")),
 98→  });
 99→
100→  // VS Code (Continue extension uses .continue/config.json)
101→  const vscodeConfig = path.join(home, ".continue", "config.json");
102→  clients.push({
103→    name: "VS Code + Continue",
104→    clientType: "vscode-continue",
105→    configPath: vscodeConfig,
106→    exists: fs.existsSync(vscodeConfig),
107→  });
108→
109→  return clients;
110→}
111→
112→/**
113→ * Add Sequant MCP server to a client's config file.
114→ * Returns true if written, false if already configured.
115→ */
116→export function addSequantToMcpConfig(
117→  configPath: string,
118→  clientType?: McpClientType,
119→): boolean {
120→  const sequantConfig = getSequantMcpConfig({
121→    projectDir: process.cwd(),
122→    clientType,
123→  });
124→
125→  let config: Record<string, unknown> = {};
126→  if (fs.existsSync(configPath)) {
127→    try {
128→      config = JSON.parse(fs.readFileSync(configPath, "utf-8"));
129→    } catch {
130→      // Corrupt or empty file — start fresh
131→    }
132→  }
133→
134→  // Initialize mcpServers if needed
135→  if (!config.mcpServers || typeof config.mcpServers !== "object") {
136→    config.mcpServers = {};
137→  }
138→
139→  const servers = config.mcpServers as Record<string, unknown>;
140→
141→  // Check if already configured
142→  if (servers.sequant) {
143→    return false;
144→  }
145→
146→  servers.sequant = sequantConfig;
147→
148→  // Ensure parent directory exists
149→  const dir = path.dirname(configPath);
150→  if (!fs.existsSync(dir)) {
151→    fs.mkdirSync(dir, { recursive: true });
152→  }
153→
154→  fs.writeFileSync(configPath, JSON.stringify(config, null, 2) + "\n");
155→  return true;
156→}
